 1→import { useEffect, useMemo, useRef } from 'react';
 2→import { buildPreviewScene } from '@/three/scene/buildPreviewScene';
 3→import { buildPreviewObjectRoot } from './buildPreviewObjects';
 4→import { createPreviewViewport } from './createPreviewViewport';
 5→import styles from './ThreePreviewPanel.module.css';
 6→
 7→export default function ThreePreviewPanel({ project, activeFloorId, className = '' }) {
 8→  const viewportRef = useRef(null);
 9→  const containerRef = useRef(null);
10→  const resizeObserverRef = useRef(null);
11→  const sceneDescriptor = useMemo(() => buildPreviewScene(project, {
12→    activeFloorId,
13→  }), [project, activeFloorId]);
14→
15→  const activeFloor = (project?.floors || []).find((floor) => floor.id === activeFloorId) || null;
16→  const visibleCount = sceneDescriptor.floors
17→    .filter((floor) => floor.visible)
18→    .reduce((count, floor) => count + floor.objects.length, 0);
19→  const visibleFloorCount = sceneDescriptor.floors.filter((floor) => floor.visible).length;
20→
21→  useEffect(() => {
22→    if (!containerRef.current) return undefined;
23→
24→    const viewport = createPreviewViewport(containerRef.current);
25→    viewportRef.current = viewport;
26→
27→    if ('ResizeObserver' in window) {
28→      const observer = new ResizeObserver(() => {
29→        viewport.resize();
30→      });
31→      observer.observe(containerRef.current);
32→      resizeObserverRef.current = observer;
33→    }
34→
35→    viewport.resize();
36→
37→    return () => {
38→      resizeObserverRef.current?.disconnect?.();
39→      resizeObserverRef.current = null;
40→      viewport.dispose();
41→      viewportRef.current = null;
42→    };
43→  }, []);
44→
45→  useEffect(() => {
46→    const viewport = viewportRef.current;
47→    if (!viewport) return;
48→
49→    const root = buildPreviewObjectRoot(sceneDescriptor, viewport.materialPalette);
50→    viewport.setWorld(root, sceneDescriptor.bounds, sceneDescriptor.groundLevel);
51→  }, [sceneDescriptor]);
52→
53→  return (
54→    <section className={`${styles.panel} ${className}`}>
55→      <div className={styles.header}>
56→        <div className={styles.titleGroup}>
57→          <span className={styles.eyebrow}>3D Preview</span>
58→          <span className={styles.title}>
59→            {activeFloor ? `${activeFloor.name} selected · ${visibleFloorCount} floors · ${visibleCount} objects` : 'No active floor'}
60→          </span>
61→        </div>
62→        <div className={styles.actions}>
63→          <button
64→            type="button"
65→            className={styles.button}
66→            onClick={() => viewportRef.current?.resetView()}
67→          >
68→            Reset View
69→          </button>
70→        </div>
71→      </div>
72→
73→      <div className={styles.viewportWrap}>
74→        <div ref={containerRef} className={styles.viewport} />
75→        {!sceneDescriptor.hasVisibleObjects && (
76→          <div className={styles.emptyState}>
77→            <span className={styles.emptyTitle}>Scene Empty</span>
78→            <span className={styles.emptyBody}>
79→              Add walls, slab, columns, beams, stairs, doors, or windows to populate the read-only preview.
80→            </span>
81→          </div>
82→        )}
83→      </div>
84→
85→      <div className={styles.footer}>
86→        <span>Orbit: drag · Pan: right drag · Zoom: wheel</span>
87→        <span>Perspective preview, future-ready for presets and floor visibility.</span>
88→      </div>
89→    </section>
90→  );
91→}
